14	export const runScenario = (scenario: any): unknown => {
15	  const items = scenario.steps[0].items;
16	  const itemsTotal = items.reduce(
17	    (sum: number, item: any) => sum + premiumForItem(item),
18	    0,
19	  );
20	  const premium = itemsTotal + PROCESSING_FEE;
21	  return { results: [{ premium }] };
22	};
